// Generated from bejamas-juno style registry. Do not edit packages/ui/src/components/input/Input.astro directly.
/**
 * @component Input
 * @title Input
 * @description Base input field used in forms.
 * @description A field for collecting user input.
 * @figmaUrl https://www.figma.com/design/koxai7zw5vIuBzuVxe5T2l/bejamas-ui?node-id=2589-23428&t=YFStJ3V8fXEO8QD8-4
 * @status stable
 * @since 0.1.0
 *
 * @preview
 *
 * <Input type="text" placeholder="Enter your name" />
 *
 * @usage
 *
 * ```astro nocollapse
 * ---
 * import { Input } from '@bejamas/ui/components/input';
 * ---
 * <Input type="email" placeholder="Enter your email" />
 * ```
 *
 * @examples
 *
 * ### Default
 *
 * <Input type="email" placeholder="Enter your email" />
 *
 * ### Disabled
 *
 * <Input type="email" placeholder="Enter your email" disabled />
 *
 * ### Sizes
 *
 * <div class="grid w-full max-w-sm gap-3">
 *   <div class="flex items-center gap-2">
 *     <Input size="sm" placeholder="Small input (h-8)" />
 *     <Button size="sm" variant="outline">
 *       Small
 *     </Button>
 *   </div>
 *   <div class="flex items-center gap-2">
 *     <Input placeholder="Default input (h-9)" />
 *     <Button variant="outline">Default</Button>
 *   </div>
 *   <div class="flex items-center gap-2">
 *     <Input size="lg" placeholder="Large input (h-10)" />
 *     <Button size="lg" variant="outline">
 *       Large
 *     </Button>
 *   </div>
 * </div>
 *
 * ### File
 *
 * <div class="grid w-full max-w-sm items-center gap-3">
 *   <Label htmlFor="picture">Picture</Label>
 *   <Input id="picture" type="file" />
 * </div>
 *
 * ### With Label
 *
 * <div class="grid w-full max-w-sm items-center gap-3">
 *   <Label htmlFor="email">Email</Label>
 *   <Input id="email" type="email" placeholder="Enter your email" />
 * </div>
 *
 * ### With Button
 *
 *  <div class="flex w-full max-w-sm items-center gap-2">
 *    <Input type="email" placeholder="Email" />
 *    <Button type="submit" variant="outline">
 *      Subscribe
 *    </Button>
 *  </div>
 */

import { cn } from "@bejamas/ui/lib/utils";
import { cva, type VariantProps } from "class-variance-authority";
import type { HTMLAttributes } from "astro/types";

const inputVariants = cva(
  "w-full min-w-0 outline-none file:inline-flex file:border-0 file:bg-transparent disabled:pointer-events-none disabled:cursor-not-allowed disabled:opacity-50",
  {
    variants: {
      size: {
        sm: "data-[size=sm]",
        default: "data-[size=default]",
        lg: "data-[size=lg]",
      },
    },
    defaultVariants: {
      size: "default",
    },
  },
);

type InputUiSize = NonNullable<VariantProps<typeof inputVariants>["size"]>;
type NativeInputSize = HTMLAttributes<"input">["size"];

interface Props extends Omit<HTMLAttributes<"input">, "size"> {
  size?: InputUiSize | NativeInputSize;
  nativeSize?: NativeInputSize;
}

const {
  class: className = "",
  type = "text",
  size: sizeProp,
  nativeSize,
  ...props
} = Astro.props as Props;

const isUiSize = (value: unknown): value is InputUiSize =>
  value === "sm" || value === "default" || value === "lg";

const resolvedUiSize = isUiSize(sizeProp) ? sizeProp : "default";
const resolvedNativeSize =
  nativeSize ?? (!isUiSize(sizeProp) ? sizeProp : undefined);
---

<input
  type={type}
  size={resolvedNativeSize}
  data-slot={props["data-slot"] ?? "input"}
  data-size={resolvedUiSize}
  class={cn("dark:bg-input/30 border-input focus-visible:border-ring focus-visible:ring-ring/50 aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 aria-invalid:border-destructive dark:aria-invalid:border-destructive/50 h-9 rounded-md border bg-transparent px-2.5 py-1 text-base shadow-xs transition-[color,box-shadow] file:h-7 file:text-sm file:font-medium focus-visible:ring-3 aria-invalid:ring-3 md:text-sm rounded-lg data-[size=sm]:h-8 data-[size=sm]:px-2.5 data-[size=sm]:py-1 data-[size=sm]:md:text-xs data-[size=default]:h-9 data-[size=default]:px-3 data-[size=default]:py-1 data-[size=default]:md:text-sm data-[size=lg]:h-10 data-[size=lg]:px-3.5 data-[size=lg]:py-1.5 data-[size=lg]:md:text-base", inputVariants({ size: resolvedUiSize }), className)}
  {...props}
/>
